#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Simple hash set for integers (open addressing)
#define TABLE_SIZE 200003 // a prime larger than 2*10^5

static int *table;
static char *used;

unsigned int hash_int(int x) {
    unsigned int h = (unsigned int)x;
    h ^= h >> 16;
    h *= 0x7feb352dU;
    h ^= h >> 15;
    return h;
}

void init_set() {
    table = (int*)malloc(TABLE_SIZE * sizeof(int));
    used = (char*)calloc(TABLE_SIZE, sizeof(char));
}

void clear_set() {
    free(table);
    free(used);
}

void insert_set(int x) {
    unsigned int idx = hash_int(x) % TABLE_SIZE;
    while (used[idx]) {
        if (table[idx] == x) return; // already present
        idx = (idx + 1) % TABLE_SIZE;
    }
    used[idx] = 1;
    table[idx] = x;
}

bool contains_set(int x) {
    unsigned int idx = hash_int(x) % TABLE_SIZE;
    while (used[idx]) {
        if (table[idx] == x) return true;
        idx = (idx + 1) % TABLE_SIZE;
    }
    return false;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n, m; long long c; // c can be up to 2e9, fits in 32‑bit but use 64 for safety
        scanf("%d %d %lld", &n, &m, &c);
        init_set();
        for (int i = 0; i < n; ++i) {
            int val; scanf("%d", &val);
            insert_set(val);
        }
        bool ok = false;
        for (int j = 0; j < m; ++j) {
            int val; scanf("%d", &val);
            long long need = c - val;
            if (need >= 0 && need <= 1000000000 && contains_set((int)need)) {
                ok = true;
            }
        }
        printf(ok ? "YES\n" : "NO\n");
        clear_set();
    }
    return 0;
}

