#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); m = int(next(it)); c = int(next(it))
        a_set = set()
        for _ in range(n):
            a_set.add(int(next(it)))
        ok = False
        for _ in range(m):
            b = int(next(it))
            need = c - b
            if need in a_set:
                ok = True
        out_lines.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

